import{_ as t,o,c as m,a3 as p}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"18. Types Of Employment","description":"","frontmatter":{"title":"18. Types Of Employment","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["employment"]},"headers":[],"relativePath":"ebas/mspp/employment/18-types-of-employment.md","filePath":"ebas/mspp/employment/18-types-of-employment.md"}'),a={name:"ebas/mspp/employment/18-types-of-employment.md"};function s(l,e,n,r,i,y){return o(),m("div",null,[...e[0]||(e[0]=[p('<h1 id="_18-types-of-employment" tabindex="-1">18. Types Of Employment <a class="header-anchor" href="#_18-types-of-employment" aria-label="Permalink to &quot;18. Types Of Employment&quot;">​</a></h1><p>Employees under this Agreement shall be employed in any one of the following categories:</p><p><strong>a.</strong> full-time Employees;</p><p><strong>b.</strong> regular part-time Employees;</p><p><strong>c.</strong> casual Employees; or</p><p><strong>d.</strong> fixed term Employees. At the time of engagement an Employer shall inform each Employee of the terms of their engagement, and in particular, whether they are to be Full-Time, Regular Part-Time, or Casual Employees.</p><p>Plain language terms: employment types, full time, part time, casual, fixed term.</p>',7)])])}const _=t(a,[["render",s]]);export{c as __pageData,_ as default};
